	private readonly tableName = TABLE_NAME_STYLE_ALTERNATIVES;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async create({
		data,
	}: {
		data: IStyleAlternativeCreate;
	}): Promise<IStyleAlternativeBase> {
		const _id = randomUUID();

		const insertData: IStyleAlternativeCreate & { _id: IStyleAlternativeBase['_id'] } = {
			...data,
			_id,
